changeSet.sql:
CREATE INDEX IF NOT EXISTS idx_patients_tenant_id_deleted
ON patients(tenant_id, id, deleted_at)
WHERE deleted_at IS NULL;

CREATE INDEX IF NOT EXISTS idx_patients_tenant_active
ON patients(tenant_id)
WHERE deleted_at IS NULL;

CREATE INDEX IF NOT EXISTS idx_patients_tenant_lastname_active
ON patients(tenant_id, last_name)
WHERE deleted_at IS NULL;

changeSet.rollback:
DROP INDEX IF EXISTS idx_patients_tenant_id_deleted;
DROP INDEX IF EXISTS idx_patients_tenant_active;
DROP INDEX IF EXISTS idx_patients_tenant_lastname_active;
